    'ArmPlan': 'ArmEnvironmentSerializationContext.Default.ArmPlan',
    'OperationStatusResult': 'ArmEnvironmentSerializationContext.Default.OperationStatusResult',
    'ExtendedLocation': 'ArmEnvironmentSerializationContext.Default.ExtendedLocation',
    'SubResource': 'ArmEnvironmentSerializationContext.Default.SubResource',
    'ResponseError': 'ArmEnvironmentSerializationContext.Default.ResponseError',
}

def find_matching_paren(s, start):
    """Find matching closing paren, handling nesting"""
    depth = 0
    i = start
    while i < len(s):
        if s[i] == '(':
            depth += 1
        elif s[i] == ')':
            depth -= 1
            if depth == 0:
                return i
        i += 1
    return -1

def replace_deserialize(content, typename, ctx_prop):
    """Replace JsonSerializer.Deserialize<Type>(...) with JsonSerializer.Deserialize(..., ctx_prop)"""
    search = f'JsonSerializer.Deserialize<{typename}>'
    result = []
    i = 0
    while i < len(content):
        idx = content.find(search, i)
        if idx == -1:
            result.append(content[i:])
            break
        result.append(content[i:idx])
        # Find the opening paren after the generic
        paren_start = idx + len(search)
        if paren_start < len(content) and content[paren_start] == '(':
            paren_end = find_matching_paren(content, paren_start)
            if paren_end != -1:
                args = content[paren_start+1:paren_end]
                result.append(f'JsonSerializer.Deserialize({args}, {ctx_prop})')
                i = paren_end + 1
            else:
                result.append(search)
                i = paren_start
        else:
            result.append(search)
            i = paren_start
    return ''.join(result)

for root, dirs, files in os.walk('.'):
    for f in files:
        if not f.endswith('.cs'):
